  `category_id` bigint(20) unsigned DEFAULT NULL,
  `sub_category_id` bigint(20) unsigned DEFAULT NULL,
  `manufacturer_id` bigint(20) unsigned DEFAULT NULL,
  `base_price` decimal(10,2) NOT NULL,
  `cost_of_goods_sold` decimal(10,2) NOT NULL,
  `current_stock` int(10) unsigned NOT NULL DEFAULT 0,
  `manage_stock` tinyint(1) NOT NULL DEFAULT 0,
  `minimal_stock` int(10) unsigned NOT NULL DEFAULT 0,
  `is_discountable` tinyint(1) NOT NULL DEFAULT 1,
  `max_discount` decimal(10,2) DEFAULT NULL,
  `max_discount_type` varchar(255) NOT NULL DEFAULT 'percentage',
  `notify_when_out_of_stock` tinyint(1) NOT NULL DEFAULT 0,
  `available_order_types` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`available_order_types`)),
  `created_by` bigint(20) DEFAULT NULL,
  `updated_by` bigint(20) DEFAULT NULL,
  `deleted_by` bigint(20) DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `status` enum('active','inactive') NOT NULL DEFAULT 'active',
  `kitchen_id` bigint(20) unsigned DEFAULT NULL,
  `unit_id` bigint(20) unsigned DEFAULT NULL,
  `item_type` varchar(255) NOT NULL DEFAULT 'finished_product',
  `tenant_id` bigint(20) unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `products_kitchen_id_foreign` (`kitchen_id`),
  KEY `products_category_id_foreign` (`category_id`),
  KEY `products_sub_category_id_foreign` (`sub_category_id`),
  KEY `products_manufacturer_id_foreign` (`manufacturer_id`),
  KEY `products_unit_id_foreign` (`unit_id`),
  KEY `products_tenant_id_index` (`tenant_id`),
  CONSTRAINT `products_category_id_foreign` FOREIGN KEY (`category_id`) REFERENCES `pos_categories` (`id`) ON DELETE SET NULL,
  CONSTRAINT `products_kitchen_id_foreign` FOREIGN KEY (`kitchen_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
